// mm/src/pages/register.js
import React, { useMemo, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { saveAuth } from '../utils/auth';

const API_BASE =
  process.env.REACT_APP_API_BASE_URL || 'https://manuscriptmagic.fowkes.xyz/services';

function isValidEmail(email) {
  const v = String(email || '').trim();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

export default function RegisterPage() {
  const nav = useNavigate();

  const [form, setForm] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [serverMessage, setServerMessage] = useState('');

  const canSubmit = useMemo(() => {
    const okEmail = isValidEmail(form.email);
    const okPw = String(form.password || '').length >= 8;
    const okNames =
      String(form.firstName || '').trim().length > 0 &&
      String(form.lastName || '').trim().length > 0;
    return okEmail && okPw && okNames && !loading;
  }, [form, loading]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((p) => ({ ...p, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setServerMessage('');

    const firstName = String(form.firstName || '').trim();
    const lastName = String(form.lastName || '').trim();
    const email = String(form.email || '').trim();
    const password = String(form.password || '');

    if (!firstName || !lastName) {
      setError('Please enter your first and last name.');
      return;
    }
    if (!isValidEmail(email)) {
      setError('Please enter a valid email.');
      return;
    }
    if (password.length < 8) {
      setError('Password must be at least 8 characters.');
      return;
    }

    setLoading(true);
    try {
      const resp = await fetch(`${API_BASE}/register.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ firstName, lastName, email, password }),
      });

      let data = null;
      try {
        data = await resp.json();
      } catch {
        data = null;
      }

      if (!resp.ok) {
        setError(data?.message || data?.error || `Registration failed (${resp.status}).`);
        return;
      }

      const success = data?.success ?? true;
      if (!success) {
        setError(data?.message || data?.error || 'Registration failed.');
        return;
      }

      // ✅ Try to read tokens from register response
      const userId = data?.userId || data?.UserId || '';
      const accessToken = data?.accessToken || data?.AccessToken || '';
      const refreshToken = data?.refreshToken || data?.RenewalToken || '';

      if (!accessToken || !refreshToken) {
        // If your backend does NOT return tokens, use Option B below.
        setError(
          'Account created, but register response did not include tokens. Update backend to return tokens OR use auto-login fallback.'
        );
        return;
      }

      // ✅ Auto sign-in
      saveAuth({ userId, accessToken, refreshToken });

      setServerMessage(data?.message || 'Account created. Signing you in…');

      // ✅ Go to account page
      nav('/account', { replace: true });
    } catch (err) {
      console.error(err);
      setError(
        'Network/CORS error. Your backend must allow requests from http://localhost:3000 (Access-Control-Allow-Origin).'
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-slate-50 to-slate-100 flex items-center justify-center px-4 py-12">
      <div className="w-full max-w-xl bg-white border border-slate-200 rounded-2xl shadow-sm p-8">
        <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">Create your account</h1>
        <p className="mt-2 text-slate-500">Enter your details to register.</p>

        <form onSubmit={handleSubmit} className="mt-8 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700">
                First Name <span className="text-red-500">*</span>
              </label>
              <input
                name="firstName"
                value={form.firstName}
                onChange={handleChange}
                placeholder="First name"
                className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
                autoComplete="given-name"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700">
                Last Name <span className="text-red-500">*</span>
              </label>
              <input
                name="lastName"
                value={form.lastName}
                onChange={handleChange}
                placeholder="Last name"
                className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
                autoComplete="family-name"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700">
              Email <span className="text-red-500">*</span>
            </label>
            <input
              name="email"
              type="email"
              value={form.email}
              onChange={handleChange}
              placeholder="you@email.com"
              className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
              autoComplete="email"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700">
              Password <span className="text-red-500">*</span>
            </label>
            <input
              name="password"
              type="password"
              value={form.password}
              onChange={handleChange}
              placeholder="At least 8 characters"
              className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
              autoComplete="new-password"
            />
          </div>

          {error ? <div className="text-sm text-red-600">{error}</div> : null}
          {serverMessage ? <div className="text-sm text-emerald-700">{serverMessage}</div> : null}

          <button
            type="submit"
            disabled={!canSubmit}
            className={[
              'w-full py-3 rounded-md text-white font-semibold',
              canSubmit ? 'bg-blue-600 hover:bg-blue-700' : 'bg-slate-300 cursor-not-allowed',
            ].join(' ')}
          >
            {loading ? 'Creating account…' : 'Register'}
          </button>

          <div className="text-sm text-slate-600 text-center">
            Already have an account?{' '}
            <Link to="/login" className="text-blue-700 hover:underline">
              Sign in
            </Link>
          </div>
        </form>
      </div>
    </div>
  );
}
